#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <sys/time.h>
#include <omp.h>

#include "../common.h"
#include "./kernel_gpu_opencl_wrapper.h"

static double elapsed_ms_wrapper1(const struct timeval *start, const struct timeval *end) {
	return (double)(end->tv_sec - start->tv_sec) * 1000.0 +
	       (double)(end->tv_usec - start->tv_usec) / 1000.0;
}

void 
kernel_gpu_opencl_wrapper(	record *records,
							long records_mem,
							knode *knodes,
							long knodes_elem,
							long knodes_mem,

							int order,
							long maxheight,
							int count,

							long *currKnode,
							long *offset,
							int *keys,
							record *ans)
{
#ifdef TIMING
	struct timeval tv_total_start, tv_total_end;
	struct timeval tv_init_end;
	struct timeval tv_mem_alloc_end;
	struct timeval tv_h2d_end;
	struct timeval tv_kernel_end;
	struct timeval tv_d2h_end;
	struct timeval tv_close_start, tv_close_end;
	float init_time = 0.0f, mem_alloc_time = 0.0f, h2d_time = 0.0f, kernel_time = 0.0f,
		  d2h_time = 0.0f, close_time = 0.0f, total_time = 0.0f;
	gettimeofday(&tv_total_start, NULL);
#endif

	printf("Platform: OpenMP\n");
	printf("Device num: %u\n", 1U);
	printf("Creating CPU Context\n");
	printf("Device: OpenMP\n");
	printf("-----OpenCL Compiler Output-----\n");
	printf("--------------------------------\n");

#ifdef TIMING
	gettimeofday(&tv_init_end, NULL);
	init_time = (float)elapsed_ms_wrapper1(&tv_total_start, &tv_init_end);
#endif

	record *recordsD = (record *)malloc((size_t)records_mem);
	knode *knodesD = (knode *)malloc((size_t)knodes_mem);
	long *currKnodeD = (long *)malloc((size_t)count * sizeof(long));
	long *offsetD = (long *)malloc((size_t)count * sizeof(long));
	int *keysD = (int *)malloc((size_t)count * sizeof(int));
	record *ansD = (record *)malloc((size_t)count * sizeof(record));

#ifdef TIMING
	gettimeofday(&tv_mem_alloc_end, NULL);
	mem_alloc_time = (float)elapsed_ms_wrapper1(&tv_init_end, &tv_mem_alloc_end);
#endif

	memcpy(recordsD, records, (size_t)records_mem);
	memcpy(knodesD, knodes, (size_t)knodes_mem);
	memcpy(currKnodeD, currKnode, (size_t)count * sizeof(long));
	memcpy(offsetD, offset, (size_t)count * sizeof(long));
	memcpy(keysD, keys, (size_t)count * sizeof(int));
	memcpy(ansD, ans, (size_t)count * sizeof(record));

#ifdef TIMING
	gettimeofday(&tv_h2d_end, NULL);
	h2d_time = (float)elapsed_ms_wrapper1(&tv_mem_alloc_end, &tv_h2d_end);
#endif

	{
		size_t local_work_size[1];
		size_t global_work_size[1];
		int threads_per_block = order < 1024 ? order : 1024;
		local_work_size[0] = (size_t)threads_per_block;
		global_work_size[0] = (size_t)count * local_work_size[0];

		printf("# of blocks = %d, # of threads/block = %d (ensure that device can handle)\n",
			   (int)(global_work_size[0] / local_work_size[0]), (int)local_work_size[0]);

		#pragma omp parallel for schedule(static)
		for (int bid = 0; bid < count; bid++) {
			long curr = currKnodeD[bid];
			long off = offsetD[bid];

			for (long level = 0; level < maxheight; level++) {
				long next_off = off;
				for (int thid = 0; thid < threads_per_block; thid++) {
					if ((knodesD[curr].keys[thid] <= keysD[bid]) &&
						(knodesD[curr].keys[thid + 1] > keysD[bid])) {
						if (knodesD[off].indices[thid] < knodes_elem) {
							next_off = knodesD[off].indices[thid];
						}
					}
				}
				off = next_off;
				curr = off;
			}

			currKnodeD[bid] = curr;
			offsetD[bid] = off;

			for (int thid = 0; thid < threads_per_block; thid++) {
				if (knodesD[curr].keys[thid] == keysD[bid]) {
					ansD[bid].value = recordsD[knodesD[curr].indices[thid]].value;
				}
			}
		}
	}

#ifdef TIMING
	gettimeofday(&tv_kernel_end, NULL);
	kernel_time = (float)elapsed_ms_wrapper1(&tv_h2d_end, &tv_kernel_end);
#endif

	memcpy(ans, ansD, (size_t)count * sizeof(record));

#ifdef TIMING
	gettimeofday(&tv_d2h_end, NULL);
	d2h_time = (float)elapsed_ms_wrapper1(&tv_kernel_end, &tv_d2h_end);
	gettimeofday(&tv_close_start, NULL);
#endif

	free(recordsD);
	free(knodesD);
	free(currKnodeD);
	free(offsetD);
	free(keysD);
	free(ansD);

#ifdef TIMING
	gettimeofday(&tv_close_end, NULL);
	close_time = (float)elapsed_ms_wrapper1(&tv_close_start, &tv_close_end);
	tv_total_end = tv_close_end;
	total_time = (float)elapsed_ms_wrapper1(&tv_total_start, &tv_total_end);

	printf("Time spent in different stages of GPU_CUDA KERNEL:\n");
	printf("Init: %f\n", init_time);
	printf("MemAlloc: %f\n", mem_alloc_time);
	printf("HtoD: %f\n", h2d_time);
	printf("Exec: %f\n", kernel_time);
	printf("DtoH: %f\n", d2h_time);
	printf("Close: %f\n", close_time);
	printf("Total: %f\n", total_time);
#endif
}

