void 
kernel_gpu_opencl_wrapper_2(knode *knodes,
							long knodes_elem,
							long knodes_mem,

							int order,
							long maxheight,
							int count,

							long *currKnode,
							long *offset,
							long *lastKnode,
							long *offset_2,
							int *start,
							int *end,
							int *recstart,
							int *reclength)
{
#ifdef TIMING
	struct timeval tv_total_start, tv_total_end;
	struct timeval tv_init_end;
	struct timeval tv_mem_alloc_end;
	struct timeval tv_h2d_end;
	struct timeval tv_kernel_end;
	struct timeval tv_d2h_end;
	struct timeval tv_close_start, tv_close_end;
	float init_time = 0.0f, mem_alloc_time = 0.0f, h2d_time = 0.0f, kernel_time = 0.0f,
		  d2h_time = 0.0f, close_time = 0.0f, total_time = 0.0f;
	gettimeofday(&tv_total_start, NULL);
#endif

	printf("Platform: OpenMP\n");
	printf("Device num: %u\n", 1U);
	printf("Creating CPU Context\n");
	printf("Device: OpenMP\n");
	printf("-----OpenCL Compiler Output-----\n");
	printf("--------------------------------\n");

#ifdef TIMING
	gettimeofday(&tv_init_end, NULL);
	init_time = (float)elapsed_ms_wrapper2(&tv_total_start, &tv_init_end);
#endif

	knode *knodesD = (knode *)malloc((size_t)knodes_mem);
	long *currKnodeD = (long *)malloc((size_t)count * sizeof(long));
	long *offsetD = (long *)malloc((size_t)count * sizeof(long));
	long *lastKnodeD = (long *)malloc((size_t)count * sizeof(long));
	long *offset_2D = (long *)malloc((size_t)count * sizeof(long));
	int *startD = (int *)malloc((size_t)count * sizeof(int));
	int *endD = (int *)malloc((size_t)count * sizeof(int));
	int *ansDStart = (int *)malloc((size_t)count * sizeof(int));
	int *ansDLength = (int *)malloc((size_t)count * sizeof(int));

#ifdef TIMING
	gettimeofday(&tv_mem_alloc_end, NULL);
	mem_alloc_time = (float)elapsed_ms_wrapper2(&tv_init_end, &tv_mem_alloc_end);
#endif

	memcpy(knodesD, knodes, (size_t)knodes_mem);
	memcpy(currKnodeD, currKnode, (size_t)count * sizeof(long));
	memcpy(offsetD, offset, (size_t)count * sizeof(long));
	memcpy(lastKnodeD, lastKnode, (size_t)count * sizeof(long));
	memcpy(offset_2D, offset_2, (size_t)count * sizeof(long));
	memcpy(startD, start, (size_t)count * sizeof(int));
	memcpy(endD, end, (size_t)count * sizeof(int));
	memcpy(endD, end, (size_t)count * sizeof(int));
	memcpy(ansDLength, reclength, (size_t)count * sizeof(int));

#ifdef TIMING
	gettimeofday(&tv_h2d_end, NULL);
	h2d_time = (float)elapsed_ms_wrapper2(&tv_mem_alloc_end, &tv_h2d_end);
#endif

	{
		size_t local_work_size[1];
		size_t global_work_size[1];
		int threads_per_block = order < 1024 ? order : 1024;
		local_work_size[0] = (size_t)threads_per_block;
		global_work_size[0] = (size_t)count * local_work_size[0];

		printf("# of blocks = %d, # of threads/block = %d (ensure that device can handle)\n",
			   (int)(global_work_size[0] / local_work_size[0]), (int)local_work_size[0]);

		#pragma omp parallel for schedule(static)
		for (int bid = 0; bid < count; bid++) {
			long curr = currKnodeD[bid];
			long off = offsetD[bid];
			long last = lastKnodeD[bid];
			long off2 = offset_2D[bid];

			for (long level = 0; level < maxheight; level++) {
				long next_off = off;
				long next_off2 = off2;

				for (int thid = 0; thid < threads_per_block; thid++) {
					if ((knodesD[curr].keys[thid] <= startD[bid]) &&
						(knodesD[curr].keys[thid + 1] > startD[bid])) {
						if (knodesD[curr].indices[thid] < knodes_elem) {
							next_off = knodesD[curr].indices[thid];
						}
					}
					if ((knodesD[last].keys[thid] <= endD[bid]) &&
						(knodesD[last].keys[thid + 1] > endD[bid])) {
						if (knodesD[last].indices[thid] < knodes_elem) {
							next_off2 = knodesD[last].indices[thid];
						}
					}
				}

				off = next_off;
				off2 = next_off2;
				curr = off;
				last = off2;
			}

			currKnodeD[bid] = curr;
			offsetD[bid] = off;
			lastKnodeD[bid] = last;
			offset_2D[bid] = off2;

			for (int thid = 0; thid < threads_per_block; thid++) {
				if (knodesD[curr].keys[thid] == startD[bid]) {
					ansDStart[bid] = knodesD[curr].indices[thid];
				}
			}

			for (int thid = 0; thid < threads_per_block; thid++) {
				if (knodesD[last].keys[thid] == endD[bid]) {
					ansDLength[bid] = knodesD[last].indices[thid] - ansDStart[bid] + 1;
				}
			}
		}
	}

#ifdef TIMING
	gettimeofday(&tv_kernel_end, NULL);
	kernel_time = (float)elapsed_ms_wrapper2(&tv_h2d_end, &tv_kernel_end);
#endif

	memcpy(recstart, ansDStart, (size_t)count * sizeof(int));
	memcpy(reclength, ansDLength, (size_t)count * sizeof(int));

#ifdef TIMING
	gettimeofday(&tv_d2h_end, NULL);
	d2h_time = (float)elapsed_ms_wrapper2(&tv_kernel_end, &tv_d2h_end);
	gettimeofday(&tv_close_start, NULL);
#endif

	free(knodesD);
	free(currKnodeD);
	free(offsetD);
	free(lastKnodeD);
	free(offset_2D);
	free(startD);
	free(endD);
	free(ansDStart);
	free(ansDLength);

